#!/usr/bin/env seiscomp-python
# AUTO-GENERATED by sceasyquake/install.sh – edit source in sceasyquake/bin/sceasyquake-stream.py
"""sceasyquake – continuous ML pick publisher for SeisComP.

This module runs as a standard ``seiscomp.Client.Application``.  It:

1. Reads its configuration from SeisComP's config system (scconfig /
   ``$SEISCOMP_ROOT/etc/sceasyquake.cfg``).
2. Subscribes to SeisComP's SeedLink server for waveform data.
3. Runs inference using PhaseNet (or another easyQuake predictor).
4. Publishes ``DataModel.Pick`` objects to the SeisComP messaging bus on the
   ``PICK`` group – in exactly the same way as ``scautopick``.

Starting the module::

    seiscomp exec sceasyquake      # managed by SeisComP daemon
    # or directly:
    sceasyquake-stream.py -H localhost --console=1 -v

Configuration (``$SEISCOMP_ROOT/etc/sceasyquake.cfg``)::

    # SeedLink server (usually the local seiscomp-seedlink)
    seedlink.host = localhost
    seedlink.port = 18000

    # Stream selector list (NET.STA.LOC.CHA or wildcards)
    # Leave empty to subscribe all vertical channels (*.*..??Z)
    streams.codes = CI.*.*.HHZ,CI.*.*.EHZ

    # ML model configuration
    picker.backend    = seisbench  # seisbench | phasenet | gpd | eqtransformer | stub
    picker.model      = PhaseNet   # architecture when backend=seisbench: PhaseNet | GPD | EQTransformer
    picker.model_path =            # path to custom .pth weights; blank = use pretrained
    picker.pretrained = stead      # pretrained weight set (e.g. stead, diting)
    picker.label_order = PSN       # output channel order the model was trained with
    picker.threshold  = 0.5
    picker.device     = cpu       # cpu | cuda

    # Sliding window settings
    picker.buffer_seconds = 60
    picker.step_seconds   = 5
"""

