try:
    import seiscomp.client as sc_client    # type: ignore
    import seiscomp.system as sc_system    # type: ignore
    import seiscomp.logging as sc_log      # type: ignore
    HAS_SEISCOMP = True
except Exception:
    HAS_SEISCOMP = False
