# ---------------------------------------------------------------------------
# Predictor factory
# ---------------------------------------------------------------------------

def _make_predictor(
    backend: str,
    pretrained: str = 'stead',
    model_path: Optional[str] = None,
    model: str = 'PhaseNet',
    threshold: float = 0.5,
    gpd_threshold: float = 0.994,
    device: str = 'cpu',
    min_distance: float = 0.2,
    p_threshold: Optional[float] = None,
    s_threshold: Optional[float] = None,
    norm: Optional[str] = None,
    phases: Optional[str] = None,
    label_order: Optional[str] = None,
):
    """Instantiate and return the appropriate predictor.

    backend values (picker.backend in sceasyquake.cfg)
    ---------------------------------------------------
    seisbench              – SeisBench library; picker.model selects architecture
                             (PhaseNet | GPD | EQTransformer); picker.model_path for
                             custom weights; picker.pretrained for pretrained name.
    phasenet               – easyQuake native PhaseNet wrapper (not SeisBench).
                             model_path is passed directly to the easyQuake backend.
    gpd                    – easyQuake native GPD (TF/Keras, Ross et al. 2018).
    gpd-seisbench          – SeisBench GPD, pretrained 'original'.
    eqtransformer          – SeisBench EQTransformer, pretrained 'original'.
    eqtransformer-native   – easyQuake bundled EQTransformer (easyQuake.seisbench
                             with seisbench fallback). Normalised aliases:
                             eqtransformer-easyquake, eqt-easyquake.
    stub                   – No-op stub; useful for testing the messaging pipeline.
    """
    backend = (backend or 'seisbench').lower().replace('-', '').replace('_', '')

    if backend == 'seisbench':
        from sceasyquake.predictors.seisbench import SeisBenchPredictor
        return SeisBenchPredictor(
            model=model or 'PhaseNet',
            pretrained=pretrained,
            model_path=model_path,
            threshold=threshold,
            p_threshold=p_threshold,
            s_threshold=s_threshold,
            min_distance=min_distance,
            norm=norm,
            device=device,
            phases=phases,
            label_order=label_order,
        )

    if backend in ('phasenet', 'easyquake'):
        from sceasyquake.predictors.easyquake_phasenet import EasyQuakePhaseNetPredictor
        return EasyQuakePhaseNetPredictor(
            model_dir=model_path,
            threshold=threshold,
            p_threshold=p_threshold,
            s_threshold=s_threshold,
            device=device,
        )

    if backend == 'gpd':
        from sceasyquake.predictors.easyquake_gpd import EasyQuakeGPDPredictor
        return EasyQuakeGPDPredictor(
            threshold=gpd_threshold,
            p_threshold=p_threshold,
            s_threshold=s_threshold,
            device=device,
        )

    if backend == 'gpdseisbench':
        from sceasyquake.predictors.seisbench import SeisBenchPredictor
        return SeisBenchPredictor(
            model='GPD',
            pretrained=pretrained or 'original',
            model_path=model_path,
            threshold=gpd_threshold,
            p_threshold=p_threshold,
            s_threshold=s_threshold,
            min_distance=min_distance,
            norm=norm,
            device=device,
            phases=phases,
            label_order=label_order,
        )

    if backend == 'eqtransformer':
        from sceasyquake.predictors.seisbench import SeisBenchPredictor
        return SeisBenchPredictor(
            model='EQTransformer',
            pretrained=pretrained or 'original',
            model_path=model_path,
            threshold=threshold,
            p_threshold=p_threshold,
            s_threshold=s_threshold,
            min_distance=min_distance,
            norm=norm,
            device=device,
            phases=phases,
            label_order=label_order,
        )

    if backend in ('eqtransformernative', 'eqtransformereasyquake', 'eqteasyquake'):
        # easyQuake bundled EQTransformer (easyQuake.seisbench → seisbench fallback)
        from sceasyquake.predictors.eqtransformer import EQTransformerPredictor
        return EQTransformerPredictor(
            pretrained=pretrained or 'original',
            model_path=model_path,
            threshold=threshold,
            min_distance=min_distance,
            device=device,
        )

    if backend == 'stub':
        from sceasyquake.predictors.phasenet import PhaseNetPredictor
        return PhaseNetPredictor(backend='stub', threshold=threshold, device=device)

    log.warning("Unknown picker.backend '%s', falling back to seisbench/PhaseNet", backend)
    from sceasyquake.predictors.seisbench import SeisBenchPredictor
    return SeisBenchPredictor(
        model=model or 'PhaseNet',
        pretrained=pretrained,
        model_path=model_path,
        threshold=threshold,
        p_threshold=p_threshold,
        s_threshold=s_threshold,
        min_distance=min_distance,
        norm=norm,
        device=device,
        phases=phases,
        label_order=label_order,
    )


def _parse_stream_specs(raw: str):
    """Parse a SeisComP streams.codes-style string into a list.

    Converts ``"CI.STA1.*.HHZ,CI.STA2.*.EHZ"`` (3-part or 4-part, wildcards)
    into the ``"NET.STA.LOC.CHA"`` format accepted by
    ``SeisCompStream``.
    """
    specs = []
    for tok in raw.split(','):
        tok = tok.strip()
        if not tok:
            continue
        parts = tok.split('.')
        if len(parts) == 4:
            specs.append(tok)
        elif len(parts) == 3:
            net, sta, cha = parts
            specs.append(f'{net}.{sta}..{cha}')
        else:
            specs.append(tok)
    return specs or ['*.*..??Z']


# ---------------------------------------------------------------------------
# SeisComP Application subclass
# ---------------------------------------------------------------------------

if HAS_SEISCOMP:
    class _SceasyquakeApp(sc_client.Application):
        """Proper SeisComP module: reads config, connects to messaging, publishes picks."""

        def __init__(self):
            sc_client.Application.__init__(self, len(sys.argv), sys.argv)
            self.setMessagingEnabled(True)
            self.setDatabaseEnabled(False, False)
            # We publish picks; do not subscribe to incoming messages by default
            self.setPrimaryMessagingGroup('PICK')
            self._stop = Event()
            self._worker = None

        # ------------------------------------------------------------------
        # SeisComP lifecycle
        # ------------------------------------------------------------------

        def createCommandLineDescription(self):
            sc_client.Application.createCommandLineDescription(self)
            self.commandline().addGroup('sceasyquake')
            self.commandline().addStringOption(
                'sceasyquake', 'model',
                'Picker backend [phasenet|gpd|eqtransformer|seisbench|auto|stub]',
            )
            self.commandline().addStringOption(
                'sceasyquake', 'model-path',
                'Path to model weights (backend-specific)',
            )
            self.commandline().addStringOption(
                'sceasyquake', 'device',
                'Compute device [cpu|cuda]',
            )
            self.commandline().addStringOption(
                'sceasyquake', 'streams',
                'Comma-separated NET.STA.LOC.CHA stream selectors',
            )
            return True

        def validateParameters(self):
            if not sc_client.Application.validateParameters(self):
                return False
            return True

        def run(self):
            """Main entry point – called after messaging is connected."""
            _install_sc_log_bridge()
            from sceasyquake.stream.seiscomp_stream import SeisCompStream
            from sceasyquake.stream.worker import StreamWorker
            from sceasyquake.uploader import PickUploader

            # --- Read configuration ---
            seedlink_host = self._cfg('seedlink.host', 'localhost')
            seedlink_port = int(self._cfg('seedlink.port', '18000'))
            raw_streams = self._cfg('streams.codes', '')
            # CLI override
            try:
                cli_streams = self.commandline().optionString('streams')
                if cli_streams:
                    raw_streams = cli_streams
            except Exception:
                pass

            stream_specs = _parse_stream_specs(raw_streams)

            model_backend  = self._cfg('picker.backend', 'seisbench')
            model_arch     = self._cfg('picker.model', 'PhaseNet')
            pretrained     = self._cfg('picker.pretrained', 'stead')
            model_path     = self._cfg('picker.model_path', '') or None
            threshold      = float(self._cfg('picker.threshold', '0.5'))
            gpd_threshold  = float(self._cfg('picker.gpd_threshold', '0.994'))
            min_distance   = float(self._cfg('picker.min_distance', '0.2'))
            _p_thresh_raw  = self._cfg('picker.p_threshold', '')
            _s_thresh_raw  = self._cfg('picker.s_threshold', '')
            p_threshold    = float(_p_thresh_raw) if _p_thresh_raw else None
            s_threshold    = float(_s_thresh_raw) if _s_thresh_raw else None
            _norm_raw      = self._cfg('picker.norm', '')
            norm           = _norm_raw if _norm_raw else None
            _phases_raw    = self._cfg('picker.phases', '')
            phases         = _phases_raw if _phases_raw else None
            _label_order_raw = self._cfg('picker.label_order', '')
            label_order    = _label_order_raw if _label_order_raw else None
            device         = self._cfg('picker.device', 'cpu')
            buffer_sec     = int(self._cfg('picker.buffer_seconds', '60'))
            step_sec       = int(self._cfg('picker.step_seconds', '5'))

            # CLI overrides
            try:
                cli_model = self.commandline().optionString('model')
                if cli_model:
                    model_backend = cli_model.lower()
            except Exception:
                pass
            try:
                cli_mp = self.commandline().optionString('model-path')
                if cli_mp:
                    model_path = cli_mp
            except Exception:
                pass
            try:
                cli_dev = self.commandline().optionString('device')
                if cli_dev:
                    device = cli_dev
            except Exception:
                pass

            log.info(
                'Starting sceasyquake: SeedLink=%s:%d, streams=%s, '
                'backend=%s, model=%s, pretrained=%s, device=%s',
                seedlink_host, seedlink_port, stream_specs,
                model_backend, model_arch, pretrained, device,
            )
            log.info(
                'Picker config: threshold=%.4f p_threshold=%s s_threshold=%s '
                'min_distance=%.3f norm=%s phases=%s label_order=%s model_path=%s',
                threshold, p_threshold, s_threshold, min_distance, norm, phases,
                label_order, model_path,
            )

            # --- Wire up components ---
            uploader = PickUploader(
                connection=self.connection(),
                agency_id=self.agencyID(),
            )

            predictor = _make_predictor(
                backend=model_backend,
                model=model_arch,
                pretrained=pretrained,
                model_path=model_path,
                threshold=threshold,
                gpd_threshold=gpd_threshold,
                min_distance=min_distance,
                p_threshold=p_threshold,
                s_threshold=s_threshold,
                norm=norm,
                phases=phases,
                label_order=label_order,
                device=device,
            )
            try:
                predictor.load_model()
            except Exception as exc:
                log.warning('Could not pre-load model: %s', exc)

            worker = StreamWorker(predictor, uploader, buffer_seconds=buffer_sec, step_seconds=step_sec)
            src = SeisCompStream(
                seedlink_url=f'{seedlink_host}:{seedlink_port}',
                stream_specs=stream_specs,
            )
            src.connect()
            worker.source = src
            worker.start()
            self._worker = worker

            # Keep messaging connection alive while worker runs
            log.info('sceasyquake running – publishing picks to PICK group')
            try:
                while not self._stop.is_set():
                    time.sleep(1)
                    # Flush any pending messages (keeps heartbeat alive)
                    try:
                        self.connection().recv(0)
                    except Exception:
                        pass
            except KeyboardInterrupt:
                pass
            finally:
                log.info('sceasyquake stopping')
                worker.stop()
                src.disconnect()

            return True

        def handleClose(self):
            """Called by SeisComP on controlled shutdown."""
            self._stop.set()

        # ------------------------------------------------------------------
        # Helpers
        # ------------------------------------------------------------------

        def _cfg(self, key: str, default: str = '') -> str:
            """Read a config string, returning *default* on any error.

            For list-valued keys (e.g. streams.codes = A, B, C) SeisComP
            stores each token separately, so configGetString returns only the
            first.  We try configGetStrings first and join the results.
            """
            try:
                items = self.configGetStrings(key)
                return ','.join(items)
            except Exception:
                pass
            try:
                return self.configGetString(key)
            except Exception:
                return default


