def _run_standalone():
    """Run without SeisComP bindings; reads a minimal INI-style config."""
    import argparse
    import configparser

    parser = argparse.ArgumentParser(
        description='sceasyquake – ML pick publisher (standalone mode)',
    )
    parser.add_argument('--config', default='/home/jwalter/easyQuake_seiscomp/sceasyquake/etc/sceasyquake.conf')
    parser.add_argument('--seedlink', default='localhost:18000')
    parser.add_argument('--streams', default='', help='Comma-separated stream selectors')
    parser.add_argument('--model', default='auto')
    parser.add_argument('--model-path', default=None)
    parser.add_argument('--threshold', type=float, default=0.5)
    parser.add_argument('--device', default='cpu')
    parser.add_argument('--buffer', type=int, default=60)
    parser.add_argument('--step', type=int, default=5)
    parser.add_argument('--pick-out', default='/var/spool/sceasyquake/picks')
    parser.add_argument('--debug', action='store_true', help='Enable debug logging')
    args = parser.parse_args()

    if args.debug:
        logging.getLogger().setLevel(logging.DEBUG)
        log.setLevel(logging.DEBUG)

    # Read config file if present, CLI overrides file
    cfg = configparser.ConfigParser()
    cfg.read(args.config)

    def _get(section, key, fallback):
        try:
            return cfg.get(section, key)
        except Exception:
            return fallback

    seedlink_url = args.seedlink or _get('seedlink', 'host', 'localhost') + ':' + _get('seedlink', 'port', '18000')
    raw_streams = args.streams or _get('general', 'streams_codes', '')
    stream_specs = _parse_stream_specs(raw_streams)
    backend = args.model or _get('general', 'machine_picker', 'auto')
    threshold = args.threshold
    device = args.device
    buffer_sec = args.buffer
    step_sec = args.step

    from sceasyquake.stream.seiscomp_stream import SeisCompStream
    from sceasyquake.stream.worker import StreamWorker
    from sceasyquake.uploader import PickUploader

    log.info('Standalone mode: SeedLink=%s streams=%s backend=%s', seedlink_url, stream_specs, backend)

    uploader = PickUploader(connection=None, out_dir=args.pick_out)
    predictor = _make_predictor(
        backend=backend,
        model_path=args.model_path,
        threshold=threshold,
        device=device,
    )
    try:
        predictor.load_model()
    except Exception as exc:
        log.warning('Could not pre-load model: %s', exc)

    worker = StreamWorker(predictor, uploader, buffer_seconds=buffer_sec, step_seconds=step_sec)
    src = SeisCompStream(seedlink_url=seedlink_url, stream_specs=stream_specs)
    src.connect()
    worker.source = src
    worker.start()

    log.info('sceasyquake standalone running (picks → YAML in %s)', args.pick_out)
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        pass
    finally:
        worker.stop()
        src.disconnect()


# ---------------------------------------------------------------------------
# Entry point
# ---------------------------------------------------------------------------

if __name__ == '__main__':
    logging.basicConfig(
        level=logging.INFO,
        format='%(asctime)s %(levelname)-8s %(name)s: %(message)s',
    )
    if HAS_SEISCOMP:
        app = _SceasyquakeApp()
        sys.exit(app())
    else:
        _run_standalone()

